import{_ as t}from"./chunks/discover-search.kdi1S6L1.js";import{_ as a}from"./chunks/channel-dive.CO18S-aC.js";import{_ as i,o as s,c as r,ag as o}from"./chunks/framework._658-eYr.js";const b=JSON.parse('{"title":"Discover","description":"","frontmatter":{},"headers":[],"relativePath":"guide/discover.md","filePath":"guide/discover.md"}'),n={name:"guide/discover.md"};function l(d,e,c,h,p,u){return s(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="discover" tabindex="-1">Discover <a class="header-anchor" href="#discover" aria-label="Permalink to &quot;Discover&quot;">​</a></h1><p>The Discover panel is a YouTube research tool powered by yt-dlp. Search for videos, analyze channels, estimate earnings, and save inspiring content as ideas.</p><h2 id="searching" tabindex="-1">Searching <a class="header-anchor" href="#searching" aria-label="Permalink to &quot;Searching&quot;">​</a></h2><p>Enter a search query and press Enter. Results show video cards with thumbnails, view counts, duration, and channel info. Results load progressively — scroll down to automatically fetch more.</p><p><img src="'+t+'" alt="Discover Search"></p><div class="tip custom-block"><p class="custom-block-title">No API Key Needed</p><p>Basic search works without a YouTube API key (uses yt-dlp). Adding a key enables subscriber cap/outlier filters and channel comparison.</p></div><h2 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h2><p>All filters trigger a re-search immediately:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Options</th><th>What It Does</th></tr></thead><tbody><tr><td><strong>Sort</strong></td><td>Relevance, Most viewed, Newest</td><td>Result ordering</td></tr><tr><td><strong>Duration</strong></td><td>Any, Short (&lt;4m), Medium (4-20m), Long (20m+)</td><td>Video length filter</td></tr><tr><td><strong>Channel Size</strong></td><td>Any, &lt;1M, &lt;100K, &lt;10K, &lt;1K subs</td><td>Subscriber cap — requires API key</td></tr><tr><td><strong>Outliers</strong></td><td>All, 5x+, 10x+, 50x+</td><td>Videos with views far above the channel&#39;s average — requires API key</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Progressive Loading</p><p>Results load in batches as you scroll. With tight filters (e.g. 10x outliers + &lt;10K subs), the backend searches progressively wider — up to 6000 raw results — to find matches.</p></div><h2 id="channel-deep-dive" tabindex="-1">Channel Deep Dive <a class="header-anchor" href="#channel-deep-dive" aria-label="Permalink to &quot;Channel Deep Dive&quot;">​</a></h2><p>Click a <strong>channel name</strong> (teal link) on any video card to open the deep dive:</p><p><img src="'+a+'" alt="Channel Deep Dive"></p><p>Multi-creator videos (collabs) show each creator as a separate link once expanded. The primary channel links to the deep dive, others link to YouTube search.</p><h3 id="analytics" tabindex="-1">Analytics <a class="header-anchor" href="#analytics" aria-label="Permalink to &quot;Analytics&quot;">​</a></h3><ul><li><strong>Subscribers</strong>, <strong>Total Views</strong>, <strong>Video Count</strong></li><li><strong>Avg Views</strong>, <strong>Upload Frequency</strong>, <strong>Engagement Rate</strong></li><li><strong>Subs/Day</strong>, <strong>Shorts Ratio</strong>, <strong>Videos in Last 30 Days</strong></li><li><strong>Monetization</strong> badge</li></ul><h3 id="estimated-earnings" tabindex="-1">Estimated Earnings <a class="header-anchor" href="#estimated-earnings" aria-label="Permalink to &quot;Estimated Earnings&quot;">​</a></h3><p>Based on your channel&#39;s RPM setting (configurable in <a href="/CRAFT/guide/settings.html">Settings</a>):</p><ul><li><strong>Monthly Revenue</strong> — estimated monthly views x RPM</li><li><strong>Per Video</strong> — average views x RPM</li><li><strong>30-Day Views</strong> — projected monthly view count</li></ul><h3 id="channel-comparison" tabindex="-1">Channel Comparison <a class="header-anchor" href="#channel-comparison" aria-label="Permalink to &quot;Channel Comparison&quot;">​</a></h3><p>Inside the deep dive, click <strong>+ Add this channel</strong> to add it to the comparison table. Compare up to 3 channels side-by-side: subscribers, total views, average views, and estimated earnings per video.</p><h3 id="recent-videos" tabindex="-1">Recent Videos <a class="header-anchor" href="#recent-videos" aria-label="Permalink to &quot;Recent Videos&quot;">​</a></h3><p>Scrollable list of the channel&#39;s latest videos. Click any to view full metadata.</p><h2 id="video-detail" tabindex="-1">Video Detail <a class="header-anchor" href="#video-detail" aria-label="Permalink to &quot;Video Detail&quot;">​</a></h2><p>Click a video card to see full metadata:</p><ul><li>Views, likes, comments, duration, upload date</li><li>Full description</li><li>Tags and categories</li><li>Chapters (if available)</li><li><strong>View Transcript</strong> — fetches and displays captions</li><li><strong>Save as Idea</strong> — creates an idea with all enrichment data</li></ul><h2 id="save-as-idea" tabindex="-1">Save as Idea <a class="header-anchor" href="#save-as-idea" aria-label="Permalink to &quot;Save as Idea&quot;">​</a></h2><p>Every video card and detail view has a <strong>Save as Idea</strong> button. This creates an idea with:</p><ul><li>Video title as the idea title</li><li>Channel name in the hook</li><li>Enrichment data: views, duration, description, transcript (if fetched)</li><li>Source tracking: <code>discover</code> with the original URL</li></ul>',29)])])}const f=i(n,[["render",l]]);export{b as __pageData,f as default};
